#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define T(a) (sum[(a)-1]+(a)+L)
using namespace std;
const int N=5e4+5;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
long long sum[N],dp[N];double K[N];int n,L,h=1,t,deq[N];
inline double Cnt(int a,int b){return double(dp[a-1]+T(a)*T(a)-dp[b-1]-T(b)*T(b))/(T(a)-T(b));}
int main()
{
	n=read();L=read();rep(1,n,i)sum[i]=sum[i-1]+read();
	rep(1,n,i)
	{
		while(h<t&&K[t]>Cnt(i,deq[t]))t--;
		K[t+1]=Cnt(i,deq[t]);deq[++t]=i;
		while(h<t&&K[h+1]<((sum[i]+i)<<1))h++;
		dp[i]=dp[deq[h]-1]+(sum[i]+i-T(deq[h]))*(sum[i]+i-T(deq[h]));
	}
	
//	rep(1,n,i)rep(1,i,j)
//	{
//		dp[i]=min(dp[i],dp[j-1]+1ll*(i-j+sum[i]-sum[j-1]-L)*(i-j+sum[i]-sum[j-1]-L));
//	}
	printf("%lld\n",dp[n]);
}
